package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private CSVFormat mockFormat;

    @BeforeEach
    void setUp() {
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void testParse_withValidStringAndFormat_returnsCSVParser() throws IOException {
        String input = "a,b,c\n1,2,3";
        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            // We do not expect Assertions.notNull to throw, so just mock it to do nothing
            mockedAssertions.when(() -> Assertions.notNull(any(), any())).thenAnswer(invocation -> null);

            CSVParser parser = CSVParser.parse(input, mockFormat);

            assertNotNull(parser);
            // Verify that the parser was created with the correct format
            assertSame(mockFormat, parser.getHeaderMap() == null ? null : parser.format);
        }
    }

    @Test
    void testParse_withNullString_throwsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
                mockedAssertions.when(() -> Assertions.notNull(null, "string")).thenThrow(new NullPointerException("string"));
                CSVParser.parse(null, mockFormat);
            }
        });
        assertEquals("string", thrown.getMessage());
    }

    @Test
    void testParse_withNullFormat_throwsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
                mockedAssertions.when(() -> Assertions.notNull(any(), eq("format"))).thenThrow(new NullPointerException("format"));
                CSVParser.parse("some string", null);
            }
        });
        assertEquals("format", thrown.getMessage());
    }
}
